WebLink.url:
/apex/DailySiteJobStandard_VF
?contractId={!Site__c.ContractId__c}
&siteId={!Site__c.Id}
&retURL={!Site__c.Id}
&unitId={!IF(
    CONTAINS($User.Username,'rig') && NOT(ISBLANK(Site__c.WD_Rig__c)),
    Site__c.WD_RigId__c,
    IF(
        CONTAINS($User.Username,'camp') && NOT(ISBLANK(Site__c.WD_Camp__c)),
        Site__c.WD_CampId__c,
        'null'
    )
)}
&unitType={!IF(
    CONTAINS($User.Username,'rig') && NOT(ISBLANK(Site__c.WD_Rig__c)),
    'Rig',
    IF(
        CONTAINS($User.Username,'camp') && NOT(ISBLANK(Site__c.WD_Camp__c)),
        'Camp',
        'null'
    )
)}
&id=new
